from dataclasses import dataclass, field
from typing import Any, Callable

@dataclass
class DelegateMandate:
    task: str
    allowed_tools: list[str]          # names of tools the delegatee may use
    max_tokens: int = 4_000           # output token budget
    max_steps: int = 10               # maximum LLM calls
    context: dict[str, Any] = field(default_factory=dict)  # scoped input data

@dataclass
class DelegateResult:
    output: str
    steps_used: int
    tokens_used: int
    error: str | None = None

TOOL_REGISTRY: dict[str, Callable] = {
    "search_web":   lambda q: f"results for {q}",
    "read_file":    lambda p: f"contents of {p}",
    "write_file":   lambda p, c: f"wrote {p}",
    "call_api":     lambda url: f"response from {url}",
}

class ScopedAgent:
    """An agent that can only access its granted tool subset."""

    def __init__(self, mandate: DelegateMandate, llm) -> None:
        self.mandate = mandate
        self.llm = llm
        self._tools = {
            name: TOOL_REGISTRY[name]
            for name in mandate.allowed_tools
            if name in TOOL_REGISTRY
        }

    def run(self) -> DelegateResult:
        steps = 0
        context = self.mandate.context.copy()

        while steps < self.mandate.max_steps:
            resp = self.llm.invoke([
                {"role": "system", "content": (
                    f"You have access to these tools only: {list(self._tools.keys())}. "
                    f"Task: {self.mandate.task}"
                )},
                {"role": "user", "content": str(context)},
            ])
            steps += 1

            # If LLM signals completion, return
            if "<DONE>" in resp.content:
                return DelegateResult(
                    output=resp.content.replace("<DONE>", "").strip(),
                    steps_used=steps,
                    tokens_used=resp.usage_metadata.get("output_tokens", 0) if hasattr(resp, "usage_metadata") else 0,
                )

        return DelegateResult(
            output="",
            steps_used=steps,
            tokens_used=0,
            error="max_steps_exceeded",
        )

from langgraph.graph import StateGraph, END
from langchain_anthropic import ChatAnthropic
from langchain_core.tools import tool
from typing import TypedDict

# --- Scoped tool set for the research sub-agent ---
@tool
def search_web(query: str) -> str:
    """Search the web for information."""
    return f"Web results for: {query}"

@tool
def read_document(path: str) -> str:
    """Read a document from disk."""
    return f"Contents of: {path}"

research_tools = [search_web, read_document]  # write_file NOT included

research_llm = ChatAnthropic(model="claude-haiku-4-5-20251001").bind_tools(research_tools)

class ResearchState(TypedDict):
    question: str
    findings: str
    steps: int

def research_agent_node(state: ResearchState) -> dict:
    resp = research_llm.invoke([
        {"role": "system", "content": "Find relevant facts. Tools available: search_web, read_document only."},
        {"role": "user",   "content": state["question"]},
    ])
    return {"findings": resp.content, "steps": state["steps"] + 1}

def build_research_subgraph():
    sg = StateGraph(ResearchState)
    sg.add_node("research", research_agent_node)
    sg.set_entry_point("research")
    sg.add_edge("research", END)
    return sg.compile()

# --- Principal graph delegates to the research subgraph ---
class PrincipalState(TypedDict):
    task: str
    research_result: str
    final: str

research_subgraph = build_research_subgraph()

def delegate_research(state: PrincipalState) -> dict:
    """Delegates research to the scoped subgraph."""
    result = research_subgraph.invoke({
        "question": state["task"],
        "findings": "",
        "steps": 0,
    })
    return {"research_result": result["findings"]}

def synthesize(state: PrincipalState) -> dict:
    llm = ChatAnthropic(model="claude-sonnet-5")
    resp = llm.invoke([
        {"role": "user", "content": f"Task: {state['task']}\nResearch: {state['research_result']}\nWrite a response."},
    ])
    return {"final": resp.content}

from pydantic import BaseModel

class DelegationResult(BaseModel):
    success: bool
    output: str
    error: str | None = None
    steps_used: int = 0

    @classmethod
    def failure(cls, reason: str) -> "DelegationResult":
        return cls(success=False, output="", error=reason)

def safe_delegate(subgraph, input_state: dict) -> DelegationResult:
    """Wraps subgraph invocation so errors surface as typed results."""
    try:
        result = subgraph.invoke(input_state)
        if result.get("errors"):
            return DelegationResult(
                success=False,
                output=result.get("findings", ""),
                error="; ".join(result["errors"]),
                steps_used=result.get("steps", 0),
            )
        return DelegationResult(
            success=True,
            output=result.get("findings", ""),
            steps_used=result.get("steps", 0),
        )
    except Exception as exc:
        return DelegationResult.failure(str(exc))

# Principal node uses safe_delegate
def delegate_research_safe(state: PrincipalState) -> dict:
    result = safe_delegate(research_subgraph, {
        "question": state["task"], "findings": "", "steps": 0,
    })
    if not result.success:
        return {"research_result": "", "errors": [f"research_delegation:{result.error}"]}
    return {"research_result": result.output}
